mapper.select:
select g.id, g.name, g.category_id as categoryId, g.seller_id as sellerId, g.send_address_id as sendAddressId, g.price, g.original_price as originalPrice, g.image, g.description, g.goods_status as goodsStatus, g.`condition` as `condition`, g.delivery_type as deliveryType, g.reject_reason as rejectReason, g.update_time as updateTime, c.name as categoryName, ifnull(u.real_name, u.name) as sellerName, u.phone as sellerPhone, concat(ifnull(a.province_name, ''), ifnull(a.city_name, ''), ifnull(a.district_name, ''), ifnull(a.detail, '')) as sendAddress from goods g left join category c on g.category_id = c.id left join user u on g.seller_id = u.id left join address_book a on g.send_address_id = a.id
and g.name like concat('%', #{name}, '%')
and g.category_id = #{categoryId}
and g.seller_id = #{sellerId}
and g.goods_status = #{goodsStatus}
and g.delivery_type = #{deliveryType}
order by g.create_time desc

mapper.update:
update goods
name = #{name}, category_id = #{categoryId}, seller_id = #{sellerId}, price = #{price}, original_price = #{originalPrice}, image = #{image}, description = #{description}, goods_status = #{goodsStatus}, `condition` = #{condition}, delivery_type = #{deliveryType}, send_address_id = #{sendAddressId}, reject_reason = #{rejectReason}, update_time = #{updateTime}, update_user = #{updateUser}
where id = #{id}

